"python3 -c \"\nimport os, re\nscratch_dir = '/Users/rohan/.gemini/antigravity-ide/brain/7760f898-6df2-4143-a541-ee055682e01e/scratch'\nfiles = os.listdir(scratch_dir)\nlines_map = {}\n\nfor f in files:\n    if f.startswith('recovered_') and f.endswith('.py'):\n        filepath = os.path.join(scratch_dir, f)\n        with open(filepath, 'r', encoding='utf-8', errors='ignore') as file:\n            content = file.read()\n        for line in content.splitlines():\n            # Match formats like '1855:     def _modal_daily_menu(self):'\n            m = re.match(r'^(\\d+):\\s*(.*)$', line)\n            if m:\n                lno = int(m.group(1))\n                code_line = m.group(2)\n                # If there are duplicates, we keep the longer one or just overwrite (since they should match)\n                lines_map[lno] = code_line\n\n# Sort lines and save\nsorted_keys = sorted(lines_map.keys())\nprint('Total unique lines recovered:', len(sorted_keys))\nif sorted_keys:\n    print('Line range:', sorted_keys[0], 'to', sorted_keys[-1])\n    with open('fully_reconstructed_app_section.py', 'w') as out:\n        for k in sorted_keys:\n            out.write(f'{k}: {lines_map[k]}\\n')\n    print('Saved to fully_reconstructed_app_section.py')\n\""